#!/bin/bash
# Bootstrap the /dev skill into ~/.claude/skills/dev/
# Run this on the host or in any new container:
#   bash bootstrap_dev_skill.sh
set -e
SKILL_DIR="$HOME/.claude/skills/dev"
mkdir -p "$SKILL_DIR"

echo "Installing /dev skill to $SKILL_DIR..."

# SKILL.md
cat > "$SKILL_DIR/SKILL.md" << 'SKILLEOF'
---
name: dev
description: Start a development task using the 4-phase workflow (RFC → TODO → Human approval → TDD execution). Automatically loads relevant corpus context. Use for any Frappe or general development task.
arguments: [task]
---

You are starting a development task. Follow the 4-phase workflow strictly.

## Step 1 — Load Corpus Context

Run the following to find and search the corpus:

```bash
# Auto-generate corpus if missing
if [ ! -f corpus.jsonl ]; then
  echo "corpus.jsonl not found — generating..."
  python3 generate_corpus.py 2>/dev/null || echo "No generate_corpus.py found, skipping."
fi

# Search for relevant context
python3 search_corpus.py "$task" --top 20 2>/dev/null || echo "No search_corpus.py found."
```

Read the output carefully. These are the actual DocTypes, controllers, and APIs relevant to this task.

If no corpus tools exist, ask the user: "Should I generate a corpus.jsonl for this project first?"

## Step 2 — Phase 1: RFC (Discuss Only)

Using the corpus context above, produce a Markdown RFC covering:
- What needs to be built and why
- Which existing DocTypes/APIs are involved (reference them by name from corpus output)
- Architectural boundaries — what should NOT change
- Open questions that need human input

**Rule: No code. No file creation. Discussion only.**

## Step 3 — Phase 2: Granular TODO

Transform the RFC into a hyper-specific TODO list. Every item must follow these rules:

- **TDD First**: test item comes before implementation item
- **Absolute paths**: every file referenced uses its full workspace path
- **Implementation block**: each item describes the expected logic in detail
- **bench run-tests command**: include the exact test command for each test item

Format:
```
- [ ] TEST: <what it verifies> — `bench run-tests --app <app> --doctype "<DocType>"`
      File: /full/path/to/test_file.py
      Logic: <what the test asserts>

- [ ] IMPL: <what to implement>
      File: /full/path/to/controller.py
      Logic: <exact implementation detail>
```

## Step 4 — Phase 3: Human Gatekeeping

Present the TODO list and explicitly ask:
> "Does this TODO match what you want? Any changes before I start executing?"

**Do not proceed to Phase 4 until the user approves.**

## Step 5 — Phase 4: Execute

Work through the TODO list one item at a time:
1. Scaffold with `bench` CLI if new DocType
2. Write the failing test — run it to confirm it fails
3. Implement until `bench run-tests` passes
4. Commit with a Conventional Commit message

After each file edit, the corpus auto-updates via the PostToolUse hook.

SKILLEOF

# generate_corpus.py
echo "" | base64 -d > "$SKILL_DIR/generate_corpus.py"

# search_corpus.py
echo "" | base64 -d > "$SKILL_DIR/search_corpus.py"

# install.sh
cat > "$SKILL_DIR/install.sh" << 'INSTALLEOF'
#!/bin/bash
# Install the /dev skill and corpus tools into a new container.
#
# Usage:
#   bash install.sh                  # install globally + set up current project
#   bash install.sh --global-only    # only install the Claude skill, skip project hooks

set -e

SKILL_DIR="$HOME/.claude/skills/dev"
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
GLOBAL_ONLY=false

for arg in "$@"; do
  [[ "$arg" == "--global-only" ]] && GLOBAL_ONLY=true
done

echo "=== Installing /dev skill ==="

# 1. Copy skill files to ~/.claude/skills/dev/
mkdir -p "$SKILL_DIR"
cp "$SCRIPT_DIR/SKILL.md"             "$SKILL_DIR/SKILL.md"
cp "$SCRIPT_DIR/generate_corpus.py"   "$SKILL_DIR/generate_corpus.py"
cp "$SCRIPT_DIR/search_corpus.py"     "$SKILL_DIR/search_corpus.py"
cp "$SCRIPT_DIR/install.sh"           "$SKILL_DIR/install.sh"
echo "  [ok] Skill installed at $SKILL_DIR"

if $GLOBAL_ONLY; then
  echo ""
  echo "Done (global only). Run without --global-only inside a project to set up hooks."
  exit 0
fi

# 2. Set up project corpus tools in CWD
echo ""
echo "=== Setting up corpus in $(pwd) ==="

cp "$SKILL_DIR/generate_corpus.py" ./generate_corpus.py
cp "$SKILL_DIR/search_corpus.py"   ./search_corpus.py
echo "  [ok] generate_corpus.py and search_corpus.py copied to $(pwd)"

# 3. Generate the initial corpus
echo "  Generating corpus.jsonl..."
python3 generate_corpus.py
echo "  [ok] corpus.jsonl generated"

# 4. Set up Claude Code project hook (auto-regenerate on file edits)
mkdir -p .claude/hooks

cat > .claude/hooks/refresh_corpus.sh << 'HOOK'
#!/bin/bash
input=$(cat)
file_path=$(echo "$input" | python3 -c "
import json, sys
data = json.load(sys.stdin)
inp = data.get('tool_input', {})
print(inp.get('file_path', inp.get('path', '')))
" 2>/dev/null)

if [[ "$file_path" != *"/apps/"* ]]; then exit 0; fi
if [[ "$file_path" != *.py && "$file_path" != *.json ]]; then exit 0; fi

echo "[corpus] Change in $file_path — regenerating corpus.jsonl..." >&2
python3 "$(dirname "$0")/../../generate_corpus.py" >&2
echo "[corpus] Done." >&2
HOOK

chmod +x .claude/hooks/refresh_corpus.sh
echo "  [ok] PostToolUse hook installed at .claude/hooks/refresh_corpus.sh"

# 5. Create .claude/settings.json if it doesn't exist
if [ ! -f .claude/settings.json ]; then
  cat > .claude/settings.json << 'JSON'
{
  "hooks": {
    "PostToolUse": [
      {
        "matcher": "Edit|Write",
        "hooks": [
          {
            "type": "command",
            "command": "bash .claude/hooks/refresh_corpus.sh"
          }
        ]
      }
    ]
  }
}
JSON
  echo "  [ok] .claude/settings.json created"
else
  echo "  [skip] .claude/settings.json already exists — add hook manually if needed"
fi

echo ""
echo "=== All done ==="
echo "  /dev skill is ready. Type /dev <task description> to start."

INSTALLEOF

chmod +x "$SKILL_DIR/install.sh"
echo "[ok] Skill files installed."
echo ""
echo "Now run the project installer:"
echo "  cd <your-frappe-bench-or-project>"
echo "  bash ~/.claude/skills/dev/install.sh"
